import { GoogleGenAI, Type } from "@google/genai";
import { AIPromptResult, Mood } from "../types";

export const getAIAssistantParams = async (prompt: string): Promise<AIPromptResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Based on this lofi scene description, generate musical parameters: "${prompt}"`,
    config: {
      systemInstruction: "You are a specialized music producer assistant for Lofi Hip Hop. Convert descriptive scenes into structured musical parameters (Mood, BPM, Duration, Title). Map moods to: Chill, Night, Rainy, Focus, Coding, Sleep. Provide a calm reasoning for your choices.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          mood: { type: Type.STRING, enum: Object.values(Mood) },
          bpmRange: {
            type: Type.OBJECT,
            properties: {
              min: { type: Type.NUMBER },
              max: { type: Type.NUMBER }
            }
          },
          suggestedDuration: { type: Type.NUMBER, description: 'Seconds per track' },
          suggestedTitle: { type: Type.STRING },
          reasoning: { type: Type.STRING }
        },
        required: ["mood", "bpmRange", "suggestedDuration", "suggestedTitle", "reasoning"]
      }
    }
  });

  try {
    return JSON.parse(response.text.trim()) as AIPromptResult;
  } catch (error) {
    console.error("Failed to parse AI response", error);
    // Fallback
    return {
      mood: Mood.CHILL,
      bpmRange: { min: 80, max: 90 },
      suggestedDuration: 180,
      suggestedTitle: "Dreamscape",
      reasoning: "I defaulted to a chill vibe as I couldn't process the input correctly."
    };
  }
};

