export const batchGenerateTracks = async (
  count: number,
  params: { mood: Mood; bpmMin: number; bpmMax: number; durationSeconds: number; titleBase: string }
): Promise<Track[]> => {
  const results: Track[] = [];

  for (let i = 0; i < count; i++) {
    let attempts = 0;
    let success = false;

    while (attempts < 3 && !success) {
      try {
        const bpm = Math.floor(Math.random() * (params.bpmMax - params.bpmMin + 1)) + params.bpmMin;
        const track = await generateLofiTrack({
          mood: params.mood,
          bpm,
          durationSeconds: params.durationSeconds,
          title: count > 1 ? `${params.titleBase} (Part ${i + 1})` : params.titleBase
        });
        results.push(track);
        success = true;
      } catch (err) {
        attempts++;
        if (attempts >= 3) throw new Error("Failed to generate tracks after 3 attempts.");
      }
    }
  }

  return results;
};

