export const MixBuilder: React.FC = () => {
  const [availableTracks, setAvailableTracks] = useState<Track[]>([]);
  const [selectedTrackIds, setSelectedTrackIds] = useState<string[]>([]);
  const [mixName, setMixName] = useState('New Ambient Mix');
  const [mixMood, setMixMood] = useState(Mood.CHILL);
  const [crossfade, setCrossfade] = useState(5);
  const [showExportModal, setShowExportModal] = useState(false);
  const [exportData, setExportData] = useState<ExportData | null>(null);

  useEffect(() => {
    setAvailableTracks(getTracks());
  }, []);

  const mixTracks = useMemo(() => 
    selectedTrackIds.map(id => availableTracks.find(t => t.id === id)).filter(Boolean) as Track[]
  , [selectedTrackIds, availableTracks]);

  const totalDurationSeconds = useMemo(() => {
    if (mixTracks.length === 0) return 0;
    const baseDuration = mixTracks.reduce((acc, t) => acc + t.durationSeconds, 0);
    const fadeReductions = (mixTracks.length - 1) * crossfade;
    return Math.max(0, baseDuration - fadeReductions);
  }, [mixTracks, crossfade]);

  const isDurationValid = totalDurationSeconds >= 3600 && totalDurationSeconds <= 10800; // 60-180 mins

  const addToMix = (id: string) => setSelectedTrackIds(prev => [...prev, id]);
  const removeFromMix = (index: number) => {
    const next = [...selectedTrackIds];
    next.splice(index, 1);
    setSelectedTrackIds(next);
  };

  const generateExport = () => {
    let currentStartTime = 0;
    const timestamps: string[] = [];
    const jsonTracks: any[] = [];

    mixTracks.forEach((track, i) => {
      const minutes = Math.floor(currentStartTime / 60);
      const seconds = Math.floor(currentStartTime % 60);
      const stamp = `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
      timestamps.push(`${stamp} ${track.title}`);

      jsonTracks.push({
        id: track.id,
        title: track.title,
        startTime: currentStartTime,
        duration: track.durationSeconds
      });

      // Next track starts after this one, minus crossfade
      currentStartTime += (track.durationSeconds - crossfade);
    });

    const description = `
✨ ${mixName} ✨
A lofi hip hop mix for ${mixMood.toLowerCase()} moments.
Perfect for studying, focus, or late night atmosphere.

Tracklist:
${timestamps.join('\n')}

Enjoy the calm vibes. Don't forget to subscribe for more.
#lofi #chill #studybeats #${mixMood.toLowerCase()}
    `.trim();

    setExportData({
      timestampList: timestamps.join('\n'),
      youtubeDescription: description,
      m3uContent: "#EXTM3U\n" + mixTracks.map(t => `#EXTINF:${t.durationSeconds},${t.title}\n${t.audioUrl}`).join('\n'),
      jsonConfig: JSON.stringify({ name: mixName, tracks: jsonTracks, crossfade }, null, 2),
      titleSuggestion: `lofi hip hop radio — beats to ${mixMood.toLowerCase()}/relax to`,
      thumbnailPrompt: `Lofi Girl aesthetic, cozy bedroom with ${mixMood.toLowerCase()} window lighting, soft amber hues, cinematic lighting, 4k, digital art style`
    });
    setShowExportModal(true);
  };

  const handleSaveMix = () => {
    const mix: Mix = {
      id: `mix_${Math.random().toString(36).substr(2, 9)}`,
      userId: 'user_123',
      name: mixName,
      mood: mixMood,
      totalDurationSeconds,
      crossfadeDuration: crossfade,
      trackIds: selectedTrackIds,
      createdAt: new Date().toISOString()
    };
    saveMix(mix);
    alert("Mix saved successfully!");
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className="flex justify-between items-end">
        <div>
          <h2 className="text-3xl font-bold text-white mb-2">Mix Architect</h2>
          <p className="text-slate-400">Assemble tracks into long-running streams.</p>
        </div>
        <div className="flex space-x-3">
          <button 
            onClick={handleSaveMix}
            disabled={selectedTrackIds.length === 0}
            className="px-4 py-2 border border-slate-700 hover:bg-slate-800 text-slate-100 rounded-lg transition-all"
          >
            Save Mix
          </button>
          <button 
            onClick={generateExport}
            disabled={selectedTrackIds.length === 0}
            className="px-4 py-2 bg-amber-500 hover:bg-amber-600 text-slate-950 rounded-lg font-bold transition-all"
          >
            Export Assets
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-[700px]">
        {/* Left: Available Tracks */}
        <div className="lg:col-span-4 flex flex-col space-y-4 h-full">
          <h3 className="font-bold text-slate-400 text-sm uppercase tracking-wider flex items-center space-x-2">
            <Music2 size={16} />
            <span>Available Tracks</span>
          </h3>
          <div className="flex-1 bg-slate-900/40 border border-slate-800 rounded-2xl overflow-y-auto p-4 space-y-2">
            {availableTracks.map(track => (
              <div 
                key={track.id} 
                className="flex items-center justify-between p-3 rounded-xl bg-slate-950/50 border border-slate-800/50 hover:border-amber-500/30 group transition-all"
              >
                <div className="flex-1">
                  <div className="text-sm font-medium text-slate-100 truncate max-w-[150px]">{track.title}</div>
                  <div className="text-[10px] text-slate-500">{track.bpm} BPM • {Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                </div>
                <button 
                  onClick={() => addToMix(track.id)}
                  className="p-1.5 bg-amber-500/10 text-amber-500 rounded-lg hover:bg-amber-500 hover:text-slate-950 transition-all opacity-0 group-hover:opacity-100"
                >
                  <Plus size={16} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Center: Sequence Area */}
        <div className="lg:col-span-5 flex flex-col space-y-4 h-full">
          <h3 className="font-bold text-slate-400 text-sm uppercase tracking-wider flex items-center space-x-2">
            <Layers size={16} />
            <span>Sequence</span>
          </h3>
          <div className="flex-1 bg-slate-900 border border-slate-800 rounded-2xl overflow-y-auto p-4 space-y-3 shadow-inner">
            {mixTracks.map((track, index) => (
              <div key={`${track.id}-${index}`} className="flex items-center space-x-3 p-3 bg-slate-800/50 rounded-xl border border-slate-700/50 relative">
                <GripVertical className="text-slate-600 cursor-grab active:cursor-grabbing" size={16} />
                <span className="text-xs text-slate-500 font-mono w-4">{index + 1}.</span>
                <div className="flex-1">
                  <div className="text-sm font-semibold text-white">{track.title}</div>
                  <div className="text-[10px] text-slate-500">{track.mood} • {Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                </div>
                <button 
                  onClick={() => removeFromMix(index)}
                  className="p-1.5 text-slate-500 hover:text-rose-400 transition-colors"
                >
                  <Minus size={16} />
                </button>
              </div>
            ))}
            {mixTracks.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-slate-500 text-center p-8">
                <Plus className="w-12 h-12 mb-4 opacity-20" />
                <p>Drag tracks here or click the "+" icon to start building your mix.</p>
              </div>
            )}
          </div>
        </div>

        {/* Right: Mix Settings */}
        <div className="lg:col-span-3 space-y-6">
          <h3 className="font-bold text-slate-400 text-sm uppercase tracking-wider flex items-center space-x-2">
            <Settings size={16} />
            <span>Mix Details</span>
          </h3>
          <div className="bg-slate-900/40 border border-slate-800 rounded-2xl p-6 space-y-6">
             <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Mix Title</label>
              <input 
                type="text"
                value={mixName}
                onChange={(e) => setMixName(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm outline-none focus:border-amber-500/50"
              />
            </div>

            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Primary Mood</label>
              <select 
                value={mixMood}
                onChange={(e) => setMixMood(e.target.value as Mood)}
                className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm outline-none focus:border-amber-500/50 appearance-none"
              >
                {Object.values(Mood).map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Crossfade (0-10s): {crossfade}s</label>
              <input 
                type="range" min="0" max="10" 
                value={crossfade} 
                onChange={(e) => setCrossfade(parseInt(e.target.value))}
                className="w-full accent-amber-500 h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer" 
              />
            </div>

            <div className="pt-4 border-t border-slate-800">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-500 text-sm">Total Runtime</span>
                <span className={`text-lg font-bold ${isDurationValid ? 'text-emerald-400' : 'text-amber-400'}`}>
                  {Math.floor(totalDurationSeconds / 3600)}h {Math.floor((totalDurationSeconds % 3600) / 60)}m
                </span>
              </div>
              {!isDurationValid && mixTracks.length > 0 && (
                <div className="flex items-start space-x-2 p-3 bg-amber-500/10 border border-amber-500/20 rounded-lg text-amber-500 text-[10px] leading-relaxed">
                  <AlertTriangle size={14} className="flex-shrink-0" />
                  <span>Optimal YouTube mix duration is 60-180 minutes. Current: {Math.round(totalDurationSeconds/60)} mins.</span>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Export Modal */}
      {showExportModal && exportData && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
              <h3 className="text-xl font-bold text-white flex items-center space-x-2">
                <Download className="text-amber-500" />
                <span>Export Assets Generated</span>
              </h3>
              <button onClick={() => setShowExportModal(false)} className="text-slate-500 hover:text-white">
                <X />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* YT Details */}
                <div className="space-y-4">
                  <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center space-x-2 mb-2">
                      <Youtube size={16} className="text-rose-500" />
                      <span>YouTube Suggestion</span>
                    </h4>
                    <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-100 font-medium">
                      {exportData.titleSuggestion}
                    </div>
                  </div>

                  <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center space-x-2 mb-2">
                      <Sparkles size={16} className="text-amber-500" />
                      <span>Thumbnail Prompt</span>
                    </h4>
                    <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-300 text-sm italic italic">
                      {exportData.thumbnailPrompt}
                    </div>
                  </div>
                </div>

                {/* Description */}
                <div>
                  <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center space-x-2 mb-2">
                    <FileJson size={16} />
                    <span>Video Description</span>
                  </h4>
                  <pre className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-400 text-xs font-mono whitespace-pre-wrap overflow-y-auto max-h-[300px]">
                    {exportData.youtubeDescription}
                  </pre>
                </div>
              </div>

              <div className="pt-6 border-t border-slate-800 grid grid-cols-2 md:grid-cols-4 gap-4">
                <button className="flex items-center justify-center space-x-2 p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                  <FileJson size={20} />
                  <span className="text-sm font-semibold">JSON Config</span>
                </button>
                <button className="flex items-center justify-center space-x-2 p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                  <Music2 size={20} />
                  <span className="text-sm font-semibold">M3U Playlist</span>
                </button>
                <button className="flex items-center justify-center space-x-2 p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                  <Clock size={20} />
                  <span className="text-sm font-semibold">Timestamps</span>
                </button>
                <button className="flex items-center justify-center space-x-2 p-4 bg-amber-500 text-slate-950 rounded-2xl transition-all font-bold">
                  <Download size={20} />
                  <span className="text-sm">Download All</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

