import React, { useState, useEffect } from 'react';
import { HashRouter, Routes, Route, Navigate } from 'react-router-dom';
import { Layout } from './components/Layout';
import { Dashboard } from './components/Dashboard';
import { TrackGenerator } from './components/TrackGenerator';
import { MixBuilder } from './components/MixBuilder';
import { Settings } from './components/Settings';
import { Auth } from './components/Auth';
import { STORAGE_KEYS } from './constants';

const App: React.FC = () => {
  const [isAuthenticated, setIsAuthenticated] = useState<boolean>(() => {
    return localStorage.getItem(STORAGE_KEYS.USER) !== null;
  });

  const handleLogin = () => {
    const user = { id: 'user_123', email: 'creator@lofi.studio', createdAt: new Date().toISOString() };
    localStorage.setItem(STORAGE_KEYS.USER, JSON.stringify(user));
    setIsAuthenticated(true);
  };

  const handleLogout = () => {
    localStorage.removeItem(STORAGE_KEYS.USER);
    setIsAuthenticated(false);
  };

  if (!isAuthenticated) {
    return <Auth onLogin={handleLogin} />;
  }

  return (
    <HashRouter>
      <Layout>
        <Routes>
          <Route path="/" element={<Dashboard />} />
          <Route path="/tracks" element={<TrackGenerator />} />
          <Route path="/mixes" element={<MixBuilder />} />
          <Route path="/settings" element={<Settings />} />
          <Route path="*" element={<Navigate to="/" replace />} />
        </Routes>
      </Layout>
    </HashRouter>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { Mood, Track } from '../types';
import { MOOD_CONFIGS } from '../constants';
import { getAIAssistantParams } from '../services/geminiService';
import { batchGenerateTracks } from '../services/musicService';
import { saveTrack, getTracks, deleteTrack, toggleFavorite } from '../lib/storage';
// Added missing 'Music' icon import
import { Sparkles, Loader2, Play, Pause, Trash2, Heart, Download, Music } from 'lucide-react';

export const TrackGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [form, setForm] = useState({
    mood: Mood.CHILL,
    bpmMin: 70,
    bpmMax: 90,
    duration: 180,
    count: 3,
    titleBase: 'Night Chill'
  });
  const [tracks, setTracks] = useState<Track[]>([]);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audio] = useState(new Audio());

  useEffect(() => {
    setTracks(getTracks());
  }, []);

  const handleAiAssist = async () => {
    if (!prompt.trim()) return;
    setIsAiLoading(true);
    try {
      const result = await getAIAssistantParams(prompt);
      setForm({
        ...form,
        mood: result.mood,
        bpmMin: result.bpmRange.min,
        bpmMax: result.bpmRange.max,
        duration: result.suggestedDuration,
        titleBase: result.suggestedTitle
      });
      // You could show result.reasoning in a toast
    } catch (err) {
      console.error(err);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    try {
      const newTracks = await batchGenerateTracks(form.count, {
        mood: form.mood,
        bpmMin: form.bpmMin,
        bpmMax: form.bpmMax,
        durationSeconds: form.duration,
        titleBase: form.titleBase
      });
      newTracks.forEach(saveTrack);
      setTracks(getTracks());
    } catch (err) {
      alert("Error generating tracks. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handlePlay = (track: Track) => {
    if (playingId === track.id) {
      audio.pause();
      setPlayingId(null);
    } else {
      audio.src = track.audioUrl;
      audio.play();
      setPlayingId(track.id);
    }
  };

  const handleDelete = (id: string) => {
    deleteTrack(id);
    setTracks(getTracks());
  };

  const handleFavorite = (id: string) => {
    toggleFavorite(id);
    setTracks(getTracks());
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header>
        <h2 className="text-3xl font-bold text-white mb-2">Track Lab</h2>
        <p className="text-slate-400">Brew custom lofi beats or let AI describe the scene.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-8">
        {/* Left: Prompt Helper */}
        <div className="lg:col-span-1 space-y-6">
          <section className="bg-slate-900/40 border border-slate-800 p-6 rounded-2xl space-y-4">
            <div className="flex items-center space-x-2 text-amber-500 mb-2">
              <Sparkles className="w-5 h-5" />
              <h3 className="font-bold">Scene Prompt</h3>
            </div>
            <textarea 
              className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-sm focus:border-amber-500/50 focus:ring-1 focus:ring-amber-500/50 transition-all outline-none min-h-[120px]"
              placeholder="e.g., A rainy evening in a Kyoto tea house, steam rising from a cup, neon lights reflecting on wet pavement..."
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
            />
            <button 
              onClick={handleAiAssist}
              disabled={isAiLoading || !prompt.trim()}
              className="w-full py-2 bg-amber-500/10 hover:bg-amber-500/20 text-amber-500 border border-amber-500/20 rounded-xl text-sm font-semibold transition-all disabled:opacity-50 flex items-center justify-center space-x-2"
            >
              {isAiLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
              <span>Ask Assistant</span>
            </button>
          </section>

          {/* Configuration Form */}
          <form onSubmit={handleGenerate} className="bg-slate-900/40 border border-slate-800 p-6 rounded-2xl space-y-4">
            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Mood</label>
              <div className="grid grid-cols-2 gap-2">
                {Object.values(Mood).map(m => (
                  <button
                    key={m}
                    type="button"
                    onClick={() => setForm({...form, mood: m})}
                    className={`flex items-center space-x-2 px-3 py-2 rounded-lg text-sm transition-all border ${
                      form.mood === m 
                        ? 'bg-slate-800 border-amber-500/50 text-white' 
                        : 'border-slate-800 text-slate-400 hover:bg-slate-800/50'
                    }`}
                  >
                    {MOOD_CONFIGS[m].icon}
                    <span>{m}</span>
                  </button>
                ))}
              </div>
            </div>

            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">BPM Range ({form.bpmMin} - {form.bpmMax})</label>
              <input 
                type="range" min="60" max="120" 
                value={form.bpmMin} 
                onChange={(e) => setForm({...form, bpmMin: parseInt(e.target.value)})}
                className="w-full accent-amber-500 h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer" 
              />
            </div>

            <div className="grid grid-cols-2 gap-4">
              <div>
                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Batch Count</label>
                <input 
                  type="number" min="1" max="10"
                  value={form.count}
                  onChange={(e) => setForm({...form, count: parseInt(e.target.value)})}
                  className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2 text-sm outline-none focus:border-amber-500/50"
                />
              </div>
              <div>
                <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Duration (s)</label>
                <input 
                  type="number" step="30"
                  value={form.duration}
                  onChange={(e) => setForm({...form, duration: parseInt(e.target.value)})}
                  className="w-full bg-slate-950 border border-slate-800 rounded-lg p-2 text-sm outline-none focus:border-amber-500/50"
                />
              </div>
            </div>

            <button 
              type="submit"
              disabled={isGenerating}
              className="w-full py-4 bg-amber-500 hover:bg-amber-600 text-slate-950 rounded-xl font-bold text-lg shadow-lg shadow-amber-500/20 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center space-x-2 mt-4"
            >
              {isGenerating ? <Loader2 className="w-6 h-6 animate-spin" /> : <Music className="w-6 h-6" />}
              <span>{isGenerating ? 'Synthesizing...' : 'Generate Batch'}</span>
            </button>
          </form>
        </div>

        {/* Right: Tracks List */}
        <div className="lg:col-span-2 space-y-6">
          <section className="bg-slate-900/40 border border-slate-800 rounded-2xl overflow-hidden backdrop-blur-sm">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
              <h3 className="text-xl font-bold text-white">Your Track Library</h3>
              <div className="text-sm text-slate-500">{tracks.length} tracks total</div>
            </div>

            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="border-b border-slate-800 text-slate-500 text-xs uppercase tracking-widest font-semibold">
                    <th className="px-6 py-4">Track</th>
                    <th className="px-6 py-4">Mood</th>
                    <th className="px-6 py-4">BPM</th>
                    <th className="px-6 py-4 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {tracks.map(track => (
                    <tr key={track.id} className="group hover:bg-slate-800/30 transition-colors">
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-4">
                          <button 
                            onClick={() => handlePlay(track)}
                            className="p-2 bg-slate-800 rounded-full hover:bg-amber-500 hover:text-slate-950 transition-all"
                          >
                            {playingId === track.id ? <Pause size={16} /> : <Play size={16} />}
                          </button>
                          <div>
                            <div className="font-medium text-slate-100">{track.title}</div>
                            <div className="text-xs text-slate-500">{Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded text-xs font-medium inline-flex items-center space-x-1 ${MOOD_CONFIGS[track.mood].color}`}>
                          {MOOD_CONFIGS[track.mood].icon}
                          <span>{track.mood}</span>
                        </span>
                      </td>
                      <td className="px-6 py-4 font-mono text-sm text-slate-400">{track.bpm}</td>
                      <td className="px-6 py-4">
                        <div className="flex items-center justify-end space-x-2">
                          <button 
                            onClick={() => handleFavorite(track.id)}
                            className={`p-2 rounded-lg transition-colors ${track.isFavorite ? 'text-rose-500 bg-rose-500/10' : 'text-slate-500 hover:bg-slate-800'}`}
                          >
                            <Heart size={16} fill={track.isFavorite ? 'currentColor' : 'none'} />
                          </button>
                          <button 
                            onClick={() => handleDelete(track.id)}
                            className="p-2 text-slate-500 hover:text-rose-400 hover:bg-slate-800 rounded-lg transition-colors"
                          >
                            <Trash2 size={16} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                  {tracks.length === 0 && (
                    <tr>
                      <td colSpan={4} className="px-6 py-12 text-center text-slate-500 italic">
                        Empty library. Start generating!
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </section>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Track, Mix, Mood, ExportData } from '../types';
import { getTracks, saveMix } from '../lib/storage';
import { MOOD_CONFIGS } from '../constants';
// Added missing icon imports
import { 
  Plus, 
  Minus, 
  GripVertical, 
  Clock, 
  Download, 
  Youtube, 
  FileJson, 
  Music2,
  AlertTriangle,
  X,
  Layers,
  Settings,
  Sparkles
} from 'lucide-react';

export const MixBuilder: React.FC = () => {
  const [availableTracks, setAvailableTracks] = useState<Track[]>([]);
  const [selectedTrackIds, setSelectedTrackIds] = useState<string[]>([]);
  const [mixName, setMixName] = useState('New Ambient Mix');
  const [mixMood, setMixMood] = useState(Mood.CHILL);
  const [crossfade, setCrossfade] = useState(5);
  const [showExportModal, setShowExportModal] = useState(false);
  const [exportData, setExportData] = useState<ExportData | null>(null);

  useEffect(() => {
    setAvailableTracks(getTracks());
  }, []);

  const mixTracks = useMemo(() => 
    selectedTrackIds.map(id => availableTracks.find(t => t.id === id)).filter(Boolean) as Track[]
  , [selectedTrackIds, availableTracks]);

  const totalDurationSeconds = useMemo(() => {
    if (mixTracks.length === 0) return 0;
    const baseDuration = mixTracks.reduce((acc, t) => acc + t.durationSeconds, 0);
    const fadeReductions = (mixTracks.length - 1) * crossfade;
    return Math.max(0, baseDuration - fadeReductions);
  }, [mixTracks, crossfade]);

  const isDurationValid = totalDurationSeconds >= 3600 && totalDurationSeconds <= 10800; // 60-180 mins

  const addToMix = (id: string) => setSelectedTrackIds(prev => [...prev, id]);
  const removeFromMix = (index: number) => {
    const next = [...selectedTrackIds];
    next.splice(index, 1);
    setSelectedTrackIds(next);
  };

  const generateExport = () => {
    let currentStartTime = 0;
    const timestamps: string[] = [];
    const jsonTracks: any[] = [];

    mixTracks.forEach((track, i) => {
      const minutes = Math.floor(currentStartTime / 60);
      const seconds = Math.floor(currentStartTime % 60);
      const stamp = `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
      timestamps.push(`${stamp} ${track.title}`);

      jsonTracks.push({
        id: track.id,
        title: track.title,
        startTime: currentStartTime,
        duration: track.durationSeconds
      });

      // Next track starts after this one, minus crossfade
      currentStartTime += (track.durationSeconds - crossfade);
    });

    const description = `
✨ ${mixName} ✨
A lofi hip hop mix for ${mixMood.toLowerCase()} moments.
Perfect for studying, focus, or late night atmosphere.

Tracklist:
${timestamps.join('\n')}

Enjoy the calm vibes. Don't forget to subscribe for more.
#lofi #chill #studybeats #${mixMood.toLowerCase()}
    `.trim();

    setExportData({
      timestampList: timestamps.join('\n'),
      youtubeDescription: description,
      m3uContent: "#EXTM3U\n" + mixTracks.map(t => `#EXTINF:${t.durationSeconds},${t.title}\n${t.audioUrl}`).join('\n'),
      jsonConfig: JSON.stringify({ name: mixName, tracks: jsonTracks, crossfade }, null, 2),
      titleSuggestion: `lofi hip hop radio — beats to ${mixMood.toLowerCase()}/relax to`,
      thumbnailPrompt: `Lofi Girl aesthetic, cozy bedroom with ${mixMood.toLowerCase()} window lighting, soft amber hues, cinematic lighting, 4k, digital art style`
    });
    setShowExportModal(true);
  };

  const handleSaveMix = () => {
    const mix: Mix = {
      id: `mix_${Math.random().toString(36).substr(2, 9)}`,
      userId: 'user_123',
      name: mixName,
      mood: mixMood,
      totalDurationSeconds,
      crossfadeDuration: crossfade,
      trackIds: selectedTrackIds,
      createdAt: new Date().toISOString()
    };
    saveMix(mix);
    alert("Mix saved successfully!");
  };

  return (
    <div className="space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className="flex justify-between items-end">
        <div>
          h2 className="text-3xl font-bold text-white mb-2">Mix Architect</h2>
          <p className="text-slate-400">Assemble tracks into long-running streams.</p>
        </div>
        <div className="flex space-x-3">
          <button 
            onClick={handleSaveMix}
            disabled={selectedTrackIds.length === 0}
            className="px-4 py-2 border border-slate-700 hover:bg-slate-800 text-slate-100 rounded-lg transition-all"
          >
            Save Mix
          </button>
          <button 
            onClick={generateExport}
            disabled={selectedTrackIds.length === 0}
            className="px-4 py-2 bg-amber-500 hover:bg-amber-600 text-slate-950 rounded-lg font-bold transition-all"
          >
            Export Assets
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-8 h-[700px]">
        {/* Left: Available Tracks */}
        <div className="lg:col-span-4 flex flex-col space-y-4 h-full">
          <h3 className="font-bold text-slate-400 text-sm uppercase tracking-wider flex items-center space-x-2">
            <Music2 size={16} />
            <span>Available Tracks</span>
          </h3>
          <div className="flex-1 bg-slate-900/40 border border-slate-800 rounded-2xl overflow-y-auto p-4 space-y-2">
            {availableTracks.map(track => (
              <div 
                key={track.id} 
                className="flex items-center justify-between p-3 rounded-xl bg-slate-950/50 border border-slate-800/50 hover:border-amber-500/30 group transition-all"
              >
                <div className="flex-1">
                  <div className="text-sm font-medium text-slate-100 truncate max-w-[150px]">{track.title}</div>
                  <div className="text-[10px] text-slate-500">{track.bpm} BPM • {Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                </div>
                <button 
                  onClick={() => addToMix(track.id)}
                  className="p-1.5 bg-amber-500/10 text-amber-500 rounded-lg hover:bg-amber-500 hover:text-slate-950 transition-all opacity-0 group-hover:opacity-100"
                >
                  <Plus size={16} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Center: Sequence Area */}
        <div className="lg:col-span-5 flex flex-col space-y-4 h-full">
          <h3 className="font-bold text-slate-400 text-sm uppercase tracking-wider flex items-center space-x-2">
            <Layers size={16} />
            <span>Sequence</span>
          </h3>
          <div className="flex-1 bg-slate-900 border border-slate-800 rounded-2xl overflow-y-auto p-4 space-y-3 shadow-inner">
            {mixTracks.map((track, index) => (
              <div key={`${track.id}-${index}`} className="flex items-center space-x-3 p-3 bg-slate-800/50 rounded-xl border border-slate-700/50 relative">
                <GripVertical className="text-slate-600 cursor-grab active:cursor-grabbing" size={16} />
                <span className="text-xs text-slate-500 font-mono w-4">{index + 1}.</span>
                <div className="flex-1">
                  <div className="text-sm font-semibold text-white">{track.title}</div>
                  <div className="text-[10px] text-slate-500">{track.mood} • {Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                </div>
                <button 
                  onClick={() => removeFromMix(index)}
                  className="p-1.5 text-slate-500 hover:text-rose-400 transition-colors"
                >
                  <Minus size={16} />
                </button>
              </div>
            ))}
            {mixTracks.length === 0 && (
              <div className="h-full flex flex-col items-center justify-center text-slate-500 text-center p-8">
                <Plus className="w-12 h-12 mb-4 opacity-20" />
                <p>Drag tracks here or click the "+" icon to start building your mix.</p>
              </div>
            )}
          </div>
        </div>

        {/* Right: Mix Settings */}
        <div className="lg:col-span-3 space-y-6">
          <h3 className="font-bold text-slate-400 text-sm uppercase tracking-wider flex items-center space-x-2">
            <Settings size={16} />
            <span>Mix Details</span>
          </h3>
          <div className="bg-slate-900/40 border border-slate-800 rounded-2xl p-6 space-y-6">
             <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Mix Title</label>
              <input 
                type="text"
                value={mixName}
                onChange={(e) => setMixName(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm outline-none focus:border-amber-500/50"
              />
            </div>

            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Primary Mood</label>
              <select 
                value={mixMood}
                onChange={(e) => setMixMood(e.target.value as Mood)}
                className="w-full bg-slate-950 border border-slate-800 rounded-lg p-3 text-sm outline-none focus:border-amber-500/50 appearance-none"
              >
                {Object.values(Mood).map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>

            <div>
              <label className="block text-xs font-semibold text-slate-500 uppercase tracking-wider mb-2">Crossfade (0-10s): {crossfade}s</label>
              <input 
                type="range" min="0" max="10" 
                value={crossfade} 
                onChange={(e) => setCrossfade(parseInt(e.target.value))}
                className="w-full accent-amber-500 h-1 bg-slate-800 rounded-lg appearance-none cursor-pointer" 
              />
            </div>

            <div className="pt-4 border-t border-slate-800">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-500 text-sm">Total Runtime</span>
                <span className={`text-lg font-bold ${isDurationValid ? 'text-emerald-400' : 'text-amber-400'}`}>
                  {Math.floor(totalDurationSeconds / 3600)}h {Math.floor((totalDurationSeconds % 3600) / 60)}m
                </span>
              </div>
              {!isDurationValid && mixTracks.length > 0 && (
                <div className="flex items-start space-x-2 p-3 bg-amber-500/10 border border-amber-500/20 rounded-lg text-amber-500 text-[10px] leading-relaxed">
                  <AlertTriangle size={14} className="flex-shrink-0" />
                  <span>Optimal YouTube mix duration is 60-180 minutes. Current: {Math.round(totalDurationSeconds/60)} mins.</span>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Export Modal */}
      {showExportModal && exportData && (
        <div className="fixed inset-0 z-50 flex items-center justify-center p-4 bg-slate-950/80 backdrop-blur-sm">
          <div className="bg-slate-900 border border-slate-800 rounded-3xl w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
              <h3 className="text-xl font-bold text-white flex items-center space-x-2">
                <Download className="text-amber-500" />
                <span>Export Assets Generated</span>
              </h3>
              <button onClick={() => setShowExportModal(false)} className="text-slate-500 hover:text-white">
                <X />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                {/* YT Details */}
                <div className="space-y-4">
                  <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center space-x-2 mb-2">
                      <Youtube size={16} className="text-rose-500" />
                      <span>YouTube Suggestion</span>
                    </h4>
                    <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-100 font-medium">
                      {exportData.titleSuggestion}
                    </div>
                  </div>

                  <div>
                    <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center space-x-2 mb-2">
                      <Sparkles size={16} className="text-amber-500" />
                      <span>Thumbnail Prompt</span>
                    </h4>
                    <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-300 text-sm italic italic">
                      {exportData.thumbnailPrompt}
                    </div>
                  </div>
                </div>

                {/* Description */}
                <div>
                  <h4 className="text-sm font-bold text-slate-400 uppercase tracking-widest flex items-center space-x-2 mb-2">
                    <FileJson size={16} />
                    <span>Video Description</span>
                  </h4>
                  <pre className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-400 text-xs font-mono whitespace-pre-wrap overflow-y-auto max-h-[300px]">
                    {exportData.youtubeDescription}
                  </pre>
                </div>
              </div>

              <div className="pt-6 border-t border-slate-800 grid grid-cols-2 md:grid-cols-4 gap-4">
                <button className="flex items-center justify-center space-x-2 p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                  <FileJson size={20} />
                  <span className="text-sm font-semibold">JSON Config</span>
                </button>
                <button className="flex items-center justify-center space-x-2 p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                  <Music2 size={20} />
                  <span className="text-sm font-semibold">M3U Playlist</span>
                </button>
                <button className="flex items-center justify-center space-x-2 p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all">
                  <Clock size={20} />
                  <span className="text-sm font-semibold">Timestamps</span>
                </button>
                <button className="flex items-center justify-center space-x-2 p-4 bg-amber-500 text-slate-950 rounded-2xl transition-all font-bold">
                  <Download size={20} />
                  <span className="text-sm">Download All</span>
                </button>
              </div>
            </div>
          </div>
        </div>
      )}
    </div>
  );
};

