import React, { useState, useEffect } from 'react';
import { Mood, Track } from '../types';
import { MOOD_CONFIGS } from '../constants';
import { getAIAssistantParams } from '../services/geminiService';
import { batchGenerateTracks } from '../services/musicService';
import { saveTrack, getTracks, deleteTrack, toggleFavorite } from '../lib/storage';
import { Sparkles, Loader2, Play, Pause, Trash2, Heart, Download, Music } from 'lucide-react';

export const TrackGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [form, setForm] = useState({
    mood: Mood.CHILL,
    bpmMin: 70,
    bpmMax: 90,
    duration: 180,
    count: 3,
    titleBase: 'Night Chill'
  });
  const [tracks, setTracks] = useState<Track[]>([]);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [audio] = useState(new Audio());

  useEffect(() => {
    setTracks(getTracks());
  }, []);

  const handleAiAssist = async () => {
    if (!prompt.trim()) return;
    setIsAiLoading(true);
    try {
      const result = await getAIAssistantParams(prompt);
      setForm({
        ...form,
        mood: result.mood,
        bpmMin: result.bpmRange.min,
        bpmMax: result.bpmRange.max,
        duration: result.suggestedDuration,
        titleBase: result.suggestedTitle
      });
    } catch (err) {
      console.error(err);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    try {
      const newTracks = await batchGenerateTracks(form.count, {
        mood: form.mood,
        bpmMin: form.bpmMin,
        bpmMax: form.bpmMax,
        durationSeconds: form.duration,
        titleBase: form.titleBase
      });
      newTracks.forEach(saveTrack);
      setTracks(getTracks());
    } catch (err) {
      alert("Error generating tracks. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handlePlay = (track: Track) => {
    if (playingId === track.id) {
      audio.pause();
      setPlayingId(null);
    } else {
      audio.src = track.audioUrl;
      audio.play();
      setPlayingId(track.id);
    }
  };

  const handleDelete = (id: string) => {
    if (window.confirm("Delete this track?")) {
      deleteTrack(id);
      setTracks(getTracks());
    }
  };

  const handleFavorite = (id: string) => {
    toggleFavorite(id);
    setTracks(getTracks());
  };

  return (
    <div className="space-y-6 lg:space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header>
        <h2 className="text-2xl lg:text-3xl font-bold text-white mb-1 lg:mb-2">Track Lab</h2>
        <p className="text-slate-400 text-sm lg:text-base">Brew custom lofi beats or let AI describe the scene.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 lg:gap-8">
        {/* Left: Configuration Area */}
        <div className="lg:col-span-1 space-y-6">
          <section className="bg-slate-900/40 border border-slate-800 p-5 lg:p-6 rounded-2xl space-y-4">
            <div className="flex items-center space-x-2 text-amber-500 mb-1">
              <Sparkles className="w-5 h-5" />
              <h3 className="font-bold">Scene Prompt</h3>
            </div>
            <textarea 
              className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-sm focus:border-amber-500/50 focus:ring-1 focus:ring-amber-500/50 transition-all outline-none min-h-[100px] lg:min-h-[120px]"
              placeholder="Describe the vibe... e.g., Study session in a rainy Tokyo library"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
            />
            <button 
              onClick={handleAiAssist}
              disabled={isAiLoading || !prompt.trim()}
              className="w-full py-3 bg-amber-500/10 hover:bg-amber-500/20 text-amber-500 border border-amber-500/20 rounded-xl text-sm font-semibold transition-all disabled:opacity-50 flex items-center justify-center space-x-2"
            >
              {isAiLoading ? <Loader2 className="w-4 h-4 animate-spin" /> : <Sparkles className="w-4 h-4" />}
              <span>Ask Assistant</span>
            </button>
          </section>

          <form onSubmit={handleGenerate} className="bg-slate-900/40 border border-slate-800 p-5 lg:p-6 rounded-2xl space-y-5">
            <div>
              <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3">Vibe / Mood</label>
              <div className="grid grid-cols-2 gap-2">
                {Object.values(Mood).map(m => (
                  <button
                    key={m}
                    type="button"
                    onClick={() => setForm({...form, mood: m})}
                    className={`flex items-center justify-center space-x-2 px-3 py-2.5 rounded-xl text-sm transition-all border ${
                      form.mood === m 
                        ? 'bg-amber-500/10 border-amber-500/50 text-white' 
                        : 'border-slate-800 text-slate-500 hover:bg-slate-800/50'
                    }`}
                  >
                    {MOOD_CONFIGS[m].icon}
                    <span className="truncate">{m}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <div className="flex justify-between mb-2">
                  <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">BPM Min</label>
                  <span className="text-xs font-mono text-amber-500">{form.bpmMin}</span>
                </div>
                <input 
                  type="range" min="60" max="110" 
                  value={form.bpmMin} 
                  onChange={(e) => setForm({...form, bpmMin: parseInt(e.target.value)})}
                  className="w-full accent-amber-500 h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer" 
                />
              </div>

              <div className="grid grid-cols-2 gap-4">
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Count</label>
                  <input 
                    type="number" min="1" max="10"
                    value={form.count}
                    onChange={(e) => setForm({...form, count: parseInt(e.target.value)})}
                    className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-sm outline-none focus:border-amber-500/50"
                  />
                </div>
                <div>
                  <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Secs</label>
                  <input 
                    type="number" step="30"
                    value={form.duration}
                    onChange={(e) => setForm({...form, duration: parseInt(e.target.value)})}
                    className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-sm outline-none focus:border-amber-500/50"
                  />
                </div>
              </div>
            </div>

            <button 
              type="submit"
              disabled={isGenerating}
              className="w-full py-4 bg-amber-500 hover:bg-amber-600 text-slate-950 rounded-2xl font-bold text-base shadow-lg shadow-amber-500/20 transition-all active:scale-95 disabled:opacity-50 flex items-center justify-center space-x-2"
            >
              {isGenerating ? <Loader2 className="w-5 h-5 animate-spin" /> : <Music className="w-5 h-5" />}
              <span>{isGenerating ? 'Synthesizing...' : 'Generate Batch'}</span>
            </button>
          </form>
        </div>

        {/* Right: Tracks View */}
        <div className="lg:col-span-2 space-y-6">
          <section className="bg-slate-900/40 border border-slate-800 rounded-2xl overflow-hidden backdrop-blur-sm">
            <div className="p-5 lg:p-6 border-b border-slate-800 flex justify-between items-center">
              <h3 className="text-lg lg:text-xl font-bold text-white">Your Track Library</h3>
              <div className="text-xs text-slate-500 uppercase tracking-widest font-semibold">{tracks.length} tracks</div>
            </div>

            {/* Desktop Table View */}
            <div className="hidden md:block overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="border-b border-slate-800 text-slate-500 text-[10px] uppercase tracking-widest font-bold">
                    <th className="px-6 py-4">Track</th>
                    <th className="px-6 py-4">Mood</th>
                    <th className="px-6 py-4">BPM</th>
                    <th className="px-6 py-4 text-right">Actions</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-800/50">
                  {tracks.map(track => (
                    <tr key={track.id} className="group hover:bg-slate-800/30 transition-colors">
                      <td className="px-6 py-4">
                        <div className="flex items-center space-x-4">
                          <button 
                            onClick={() => handlePlay(track)}
                            className="p-3 bg-slate-800 rounded-full hover:bg-amber-500 hover:text-slate-950 transition-all shadow-sm"
                          >
                            {playingId === track.id ? <Pause size={18} /> : <Play size={18} />}
                          </button>
                          <div>
                            <div className="font-semibold text-slate-100">{track.title}</div>
                            <div className="text-xs text-slate-500">{Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                          </div>
                        </div>
                      </td>
                      <td className="px-6 py-4">
                        <span className={`px-2 py-1 rounded-lg text-[10px] font-bold inline-flex items-center space-x-1 ${MOOD_CONFIGS[track.mood].color}`}>
                          {MOOD_CONFIGS[track.mood].icon}
                          <span>{track.mood.toUpperCase()}</span>
                        </span>
                      </td>
                      <td className="px-6 py-4 font-mono text-sm text-slate-400">{track.bpm}</td>
                      <td className="px-6 py-4">
                        <div className="flex items-center justify-end space-x-2">
                          <button onClick={() => handleFavorite(track.id)} className={`p-2 rounded-lg transition-colors ${track.isFavorite ? 'text-rose-500 bg-rose-500/10' : 'text-slate-500 hover:bg-slate-800'}`}>
                            <Heart size={18} fill={track.isFavorite ? 'currentColor' : 'none'} />
                          </button>
                          <button onClick={() => handleDelete(track.id)} className="p-2 text-slate-500 hover:text-rose-400 hover:bg-slate-800 rounded-lg transition-colors">
                            <Trash2 size={18} />
                          </button>
                        </div>
                      </td>
                    </tr>
                  ))}
                </tbody>
              </table>
            </div>

            {/* Mobile Card List View */}
            <div className="md:hidden divide-y divide-slate-800/50">
              {tracks.map(track => (
                <div key={track.id} className="p-4 flex flex-col space-y-3">
                  <div className="flex items-center justify-between">
                    <div className="flex items-center space-x-3">
                      <button 
                        onClick={() => handlePlay(track)}
                        className="p-3 bg-amber-500 text-slate-950 rounded-2xl shadow-lg active:scale-95"
                      >
                        {playingId === track.id ? <Pause size={20} /> : <Play size={20} />}
                      </button>
                      <div>
                        <div className="font-bold text-slate-100">{track.title}</div>
                        <div className="text-[10px] text-slate-500 uppercase tracking-widest">{track.bpm} BPM • {Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                      </div>
                    </div>
                    <span className={`px-2 py-1 rounded-lg text-[10px] font-bold ${MOOD_CONFIGS[track.mood].color}`}>
                      {track.mood.toUpperCase()}
                    </span>
                  </div>
                  <div className="flex items-center justify-end space-x-4 pt-2">
                    <button onClick={() => handleFavorite(track.id)} className={`flex items-center space-x-1 text-xs px-3 py-2 rounded-xl transition-all ${track.isFavorite ? 'text-rose-500 bg-rose-500/10' : 'text-slate-500 bg-slate-800/50'}`}>
                      <Heart size={16} fill={track.isFavorite ? 'currentColor' : 'none'} />
                      <span>Favorite</span>
                    </button>
                    <button onClick={() => handleDelete(track.id)} className="flex items-center space-x-1 text-xs px-3 py-2 text-slate-500 bg-slate-800/50 rounded-xl">
