          </section>
        </div>
      </div>
    </div>
  );
};

import React, { useState, useEffect, useMemo } from 'react';
import { Track, Mix, Mood, ExportData } from '../types';
import { getTracks, saveMix } from '../lib/storage';
import { MOOD_CONFIGS } from '../constants';
import { 
  Plus, 
  Minus, 
  GripVertical, 
  Clock, 
  Download, 
  Youtube, 
  FileJson, 
  Music2,
  AlertTriangle,
  X,
  Layers,
  Settings,
  Sparkles
} from 'lucide-react';

export const MixBuilder: React.FC = () => {
  const [availableTracks, setAvailableTracks] = useState<Track[]>([]);
  const [selectedTrackIds, setSelectedTrackIds] = useState<string[]>([]);
  const [mixName, setMixName] = useState('New Ambient Mix');
  const [mixMood, setMixMood] = useState(Mood.CHILL);
  const [crossfade, setCrossfade] = useState(5);
  const [showExportModal, setShowExportModal] = useState(false);
  const [exportData, setExportData] = useState<ExportData | null>(null);

  useEffect(() => {
    setAvailableTracks(getTracks());
  }, []);

  const mixTracks = useMemo(() => 
    selectedTrackIds.map(id => availableTracks.find(t => t.id === id)).filter(Boolean) as Track[]
  , [selectedTrackIds, availableTracks]);

  const totalDurationSeconds = useMemo(() => {
    if (mixTracks.length === 0) return 0;
    const baseDuration = mixTracks.reduce((acc, t) => acc + t.durationSeconds, 0);
    const fadeReductions = (mixTracks.length - 1) * crossfade;
    return Math.max(0, baseDuration - fadeReductions);
  }, [mixTracks, crossfade]);

  const isDurationValid = totalDurationSeconds >= 3600 && totalDurationSeconds <= 10800;

  const addToMix = (id: string) => setSelectedTrackIds(prev => [...prev, id]);
  const removeFromMix = (index: number) => {
    const next = [...selectedTrackIds];
    next.splice(index, 1);
    setSelectedTrackIds(next);
  };

  const generateExport = () => {
    let currentStartTime = 0;
    const timestamps: string[] = [];
    const jsonTracks: any[] = [];

    mixTracks.forEach((track, i) => {
      const minutes = Math.floor(currentStartTime / 60);
      const seconds = Math.floor(currentStartTime % 60);
      const stamp = `${minutes.toString().padStart(2, '0')}:${seconds.toString().padStart(2, '0')}`;
      timestamps.push(`${stamp} ${track.title}`);

      jsonTracks.push({
        id: track.id,
        title: track.title,
        startTime: currentStartTime,
        duration: track.durationSeconds
      });

      currentStartTime += (track.durationSeconds - crossfade);
    });

    const description = `
✨ ${mixName} ✨
A lofi hip hop mix for ${mixMood.toLowerCase()} moments.

Tracklist:
${timestamps.join('\n')}

#lofi #chill #studybeats #${mixMood.toLowerCase()}
    `.trim();

    setExportData({
      timestampList: timestamps.join('\n'),
      youtubeDescription: description,
      m3uContent: "#EXTM3U\n" + mixTracks.map(t => `#EXTINF:${t.durationSeconds},${t.title}\n${t.audioUrl}`).join('\n'),
      jsonConfig: JSON.stringify({ name: mixName, tracks: jsonTracks, crossfade }, null, 2),
      titleSuggestion: `lofi hip hop radio — beats to ${mixMood.toLowerCase()}/relax to`,
      thumbnailPrompt: `Lofi Girl aesthetic, cozy bedroom with ${mixMood.toLowerCase()} window lighting, soft amber hues, cinematic lighting, 4k, digital art style`
    });
    setShowExportModal(true);
  };

  const handleSaveMix = () => {
    const mix: Mix = {
      id: `mix_${Math.random().toString(36).substr(2, 9)}`,
      userId: 'user_123',
      name: mixName,
      mood: mixMood,
      totalDurationSeconds,
      crossfadeDuration: crossfade,
      trackIds: selectedTrackIds,
      createdAt: new Date().toISOString()
    };
    saveMix(mix);
    alert("Mix saved successfully!");
  };

  return (
    <div className="space-y-6 lg:space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header className="flex flex-col md:flex-row md:justify-between md:items-end gap-4">
        <div>
          <h2 className="text-2xl lg:text-3xl font-bold text-white mb-1 lg:mb-2">Mix Architect</h2>
          <p className="text-slate-400 text-sm">Sequence and export your long-form streams.</p>
        </div>
        <div className="flex space-x-2 md:space-x-3">
          <button 
            onClick={handleSaveMix}
            disabled={selectedTrackIds.length === 0}
            className="flex-1 md:flex-none px-4 py-2.5 border border-slate-700 hover:bg-slate-800 text-slate-100 rounded-xl transition-all text-sm font-medium"
          >
            Save Mix
          </button>
          <button 
            onClick={generateExport}
            disabled={selectedTrackIds.length === 0}
            className="flex-1 md:flex-none px-4 py-2.5 bg-amber-500 hover:bg-amber-600 text-slate-950 rounded-xl font-bold transition-all text-sm"
          >
            Export
          </button>
        </div>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8 lg:h-[calc(100vh-200px)]">
        {/* Available Tracks */}
        <div className="lg:col-span-4 flex flex-col space-y-3 h-full overflow-hidden">
          <h3 className="font-bold text-slate-500 text-[10px] uppercase tracking-widest flex items-center space-x-2">
            <Music2 size={14} />
            <span>Library</span>
          </h3>
          <div className="flex-1 bg-slate-900/40 border border-slate-800 rounded-2xl overflow-y-auto p-4 space-y-2 max-h-[300px] lg:max-h-full">
            {availableTracks.map(track => (
              <div 
                key={track.id} 
                className="flex items-center justify-between p-3 rounded-xl bg-slate-950/50 border border-slate-800/50 hover:border-amber-500/30 group transition-all"
              >
                <div className="flex-1">
                  <div className="text-sm font-semibold text-slate-100 truncate pr-2">{track.title}</div>
                  <div className="text-[10px] text-slate-500">{track.bpm} BPM • {Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                </div>
                <button 
                  onClick={() => addToMix(track.id)}
                  className="p-2 bg-amber-500/10 text-amber-500 rounded-lg hover:bg-amber-500 hover:text-slate-950 transition-all md:opacity-0 md:group-hover:opacity-100"
                >
                  <Plus size={16} />
                </button>
              </div>
            ))}
          </div>
        </div>

        {/* Mix Sequence */}
        <div className="lg:col-span-5 flex flex-col space-y-3 h-full overflow-hidden">
          <h3 className="font-bold text-slate-500 text-[10px] uppercase tracking-widest flex items-center space-x-2">
            <Layers size={14} />
            <span>Current Mix Sequence</span>
          </h3>
          <div className="flex-1 bg-slate-900 border border-slate-800 rounded-2xl overflow-y-auto p-4 space-y-3 shadow-inner max-h-[400px] lg:max-h-full">
            {mixTracks.map((track, index) => (
              <div key={`${track.id}-${index}`} className="flex items-center space-x-3 p-3 bg-slate-800/50 rounded-xl border border-slate-700/50">
                <GripVertical className="text-slate-600 hidden md:block" size={16} />
                <span className="text-[10px] text-slate-500 font-mono w-4">{index + 1}.</span>
                <div className="flex-1">
                  <div className="text-sm font-semibold text-white truncate">{track.title}</div>
                  <div className="text-[10px] text-slate-500 uppercase tracking-widest">{Math.floor(track.durationSeconds / 60)}:{(track.durationSeconds % 60).toString().padStart(2, '0')}</div>
                </div>
                <button 
                  onClick={() => removeFromMix(index)}
                  className="p-2 text-slate-500 hover:text-rose-400 transition-colors"
                >
                  <Minus size={18} />
                </button>
              </div>
            ))}
            {mixTracks.length === 0 && (
              <div className="h-full min-h-[150px] flex flex-col items-center justify-center text-slate-500 text-center p-8">
                <Music2 className="w-12 h-12 mb-4 opacity-10" />
                <p className="text-sm">Sequence empty. Add tracks from your library.</p>
              </div>
            )}
          </div>
        </div>

        {/* Configuration */}
        <div className="lg:col-span-3 space-y-4 h-full flex flex-col">
          <h3 className="font-bold text-slate-500 text-[10px] uppercase tracking-widest flex items-center space-x-2">
            <Settings size={14} />
            <span>Mix Params</span>
          </h3>
          <div className="bg-slate-900/40 border border-slate-800 rounded-2xl p-5 space-y-5 flex-1">
             <div>
              <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Mix Title</label>
              <input 
                type="text"
                value={mixName}
                onChange={(e) => setMixName(e.target.value)}
                className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-sm outline-none focus:border-amber-500/50"
              />
            </div>

            <div>
              <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-2">Primary Vibe</label>
              <select 
                value={mixMood}
                onChange={(e) => setMixMood(e.target.value as Mood)}
                className="w-full bg-slate-950 border border-slate-800 rounded-xl p-3 text-sm outline-none focus:border-amber-500/50 appearance-none text-slate-200"
              >
                {Object.values(Mood).map(m => <option key={m} value={m}>{m}</option>)}
              </select>
            </div>

            <div>
              <div className="flex justify-between mb-2">
                <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">Crossfade</label>
                <span className="text-xs font-mono text-amber-500">{crossfade}s</span>
              </div>
              <input 
                type="range" min="0" max="10" 
                value={crossfade} 
                onChange={(e) => setCrossfade(parseInt(e.target.value))}
                className="w-full accent-amber-500 h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer" 
              />
            </div>

            <div className="pt-5 border-t border-slate-800 mt-auto">
              <div className="flex justify-between items-center mb-2">
                <span className="text-slate-500 text-xs font-bold uppercase tracking-widest">Total Length</span>
                <span className={`text-xl font-bold ${isDurationValid ? 'text-emerald-400' : 'text-amber-500'}`}>
                  {Math.floor(totalDurationSeconds / 3600)}h {Math.floor((totalDurationSeconds % 3600) / 60)}m
                </span>
              </div>
              {!isDurationValid && mixTracks.length > 0 && (
                <div className="flex items-start space-x-2 p-3 bg-amber-500/5 border border-amber-500/10 rounded-xl text-amber-500 text-[10px] leading-relaxed">
                  <AlertTriangle size={14} className="shrink-0" />
                  <span>Optimal mixes are 60-180m. Current: {Math.round(totalDurationSeconds/60)}m</span>
                </div>
              )}
            </div>
          </div>
        </div>
      </div>

      {/* Export Modal */}
      {showExportModal && exportData && (
        <div className="fixed inset-0 z-[100] flex items-center justify-center p-4 bg-slate-950/90 backdrop-blur-md">
          <div className="bg-slate-900 border border-slate-800 rounded-[2rem] w-full max-w-4xl max-h-[90vh] overflow-hidden flex flex-col shadow-2xl animate-in zoom-in-95 duration-300">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
              <h3 className="text-xl font-bold text-white flex items-center space-x-3">
                <div className="p-2 bg-amber-500 rounded-lg"><Download size={20} className="text-slate-950" /></div>
                <span>Export Package</span>
              </h3>
              <button onClick={() => setShowExportModal(false)} className="p-2 text-slate-500 hover:text-white transition-colors">
                <X />
              </button>
            </div>

            <div className="flex-1 overflow-y-auto p-6 md:p-8 space-y-8">
              <div className="grid grid-cols-1 md:grid-cols-2 gap-8">
                <div className="space-y-6">
                  <div>
                    <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center space-x-2 mb-3">
                      <Youtube size={14} className="text-rose-500" />
                      <span>YouTube Title</span>
                    </h4>
                    <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-100 text-sm font-medium">
                      {exportData.titleSuggestion}
                    </div>
                  </div>

                  <div>
                    <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center space-x-2 mb-3">
                      <Sparkles size={14} className="text-amber-500" />
                      <span>Visual Prompt</span>
                    </h4>
                    <div className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-400 text-xs italic leading-relaxed">
                      {exportData.thumbnailPrompt}
                    </div>
                  </div>
                </div>

                <div>
                  <h4 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center space-x-2 mb-3">
                    <FileJson size={14} />
                    <span>Video Metadata</span>
                  </h4>
                  <pre className="bg-slate-950 p-4 rounded-xl border border-slate-800 text-slate-400 text-[10px] font-mono whitespace-pre-wrap overflow-y-auto max-h-[300px]">
                    {exportData.youtubeDescription}
                  </pre>
                </div>
              </div>

              <div className="pt-6 border-t border-slate-800 grid grid-cols-1 sm:grid-cols-2 lg:grid-cols-4 gap-4">
                <button className="flex items-center justify-center space-x-2 p-4 bg-slate-800 hover:bg-slate-700 rounded-2xl transition-all group">
                  <FileJson size={20} className="text-slate-400 group-hover:text-amber-500" />
