import React, { useState, useEffect, useRef } from 'react';
import { Mood, Track } from '../types';
import { MOOD_CONFIGS } from '../constants';
import { getAIAssistantParams } from '../services/geminiService';
import { batchGenerateTracks } from '../services/musicService';
import { saveTrack, getTracks, deleteTrack, toggleFavorite } from '../lib/storage';
import { Sparkles, Loader2, Play, Pause, Trash2, Heart, Music, Clock } from 'lucide-react';

export const TrackGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [form, setForm] = useState({
    mood: Mood.CHILL,
    bpmMin: 70,
    bpmMax: 90,
    duration: 180,
    count: 3,
    titleBase: 'Night Chill'
  });
  const [tracks, setTracks] = useState<Track[]>([]);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [isAudioLoading, setIsAudioLoading] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [audioDuration, setAudioDuration] = useState(0);

  const audioRef = useRef<HTMLAudioElement>(new Audio());

  useEffect(() => {
    setTracks(getTracks());
    const audio = audioRef.current;

    const handleTimeUpdate = () => setCurrentTime(audio.currentTime);
    const handleLoadedMetadata = () => {
      setAudioDuration(audio.duration);
      setIsAudioLoading(false);
    };
    const handleWaiting = () => setIsAudioLoading(true);
    const handlePlaying = () => setIsAudioLoading(false);
    const handleEnded = () => {
      setPlayingId(null);
      setCurrentTime(0);
    };

    audio.addEventListener('timeupdate', handleTimeUpdate);
    audio.addEventListener('loadedmetadata', handleLoadedMetadata);
    audio.addEventListener('waiting', handleWaiting);
    audio.addEventListener('playing', handlePlaying);
    audio.addEventListener('ended', handleEnded);

    return () => {
      audio.pause();
      audio.removeEventListener('timeupdate', handleTimeUpdate);
      audio.removeEventListener('loadedmetadata', handleLoadedMetadata);
      audio.removeEventListener('waiting', handleWaiting);
      audio.removeEventListener('playing', handlePlaying);
      audio.removeEventListener('ended', handleEnded);
    };
  }, []);

  const handleAiAssist = async () => {
    if (!prompt.trim()) return;
    setIsAiLoading(true);
    try {
      const result = await getAIAssistantParams(prompt);
      setForm({
        ...form,
        mood: result.mood,
        bpmMin: result.bpmRange.min,
        bpmMax: result.bpmRange.max,
        duration: result.suggestedDuration,
        titleBase: result.suggestedTitle
      });
    } catch (err) {
      console.error(err);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    try {
      const newTracks = await batchGenerateTracks(form.count, {
        mood: form.mood,
        bpmMin: form.bpmMin,
        bpmMax: form.bpmMax,
        durationSeconds: form.duration,
        titleBase: form.titleBase
      });
      newTracks.forEach(saveTrack);
      setTracks(getTracks());
    } catch (err) {
      alert("Error generating tracks. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const formatTime = (seconds: number) => {
    if (isNaN(seconds)) return '0:00';
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handlePlay = (track: Track) => {
    const audio = audioRef.current;
    if (playingId === track.id) {
      audio.pause();
      setPlayingId(null);
    } else {
      setIsAudioLoading(true);
      audio.src = track.audioUrl;
      audio.play().catch(err => {
        console.error("Audio playback failed", err);
        setIsAudioLoading(false);
      });
      setPlayingId(track.id);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    audioRef.current.currentTime = time;
    setCurrentTime(time);
  };

  const handleDelete = (id: string) => {
    if (window.confirm("Delete this track?")) {
      deleteTrack(id);
      if (playingId === id) {
        audioRef.current.pause();
        setPlayingId(null);
      }
      setTracks(getTracks());
    }
  };

  const handleFavorite = (id: string) => {
    toggleFavorite(id);
    setTracks(getTracks());
  };

  return (
    <div className="space-y-6 lg:space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <header>
        <h2 className="text-2xl lg:text-3xl font-bold text-white mb-1 lg:mb-2">Track Lab</h2>
        <p className="text-slate-400 text-sm lg:text-base">Brew custom lofi beats or let AI describe the scene.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 lg:gap-8">
        {/* Left: Configuration Area */}
        <div className="lg:col-span-1 space-y-6">
          <section className="bg-slate-900/40 border border-slate-800 p-5 lg:p-6 rounded-2xl space-y-4">
            <div className="flex items-center space-x-2 text-amber-500 mb-1">
              <Sparkles className="w-5 h-5" />
              <h3 className="font-bold">Scene Prompt</h3>
            </div>
            <textarea 
              className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-sm focus:border-amber-500/50 focus:ring-1 focus:ring-amber-500/50 transition-all outline-none min-h-[100px] lg:min-h-[120px]"
              placeholder="Describe the vibe... e.g., Study session in a rainy Tokyo library"
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
            />
            <button 
              onClick={handleAiAssist}
