                    <span className="truncate">{m}</span>
                  </button>
                ))}
              </div>
            </div>

            <div className="space-y-4">
              <div>
                <div className="flex justify-between mb-2">
                  <label className="text-[10px] font-bold text-slate-500 uppercase tracking-widest">BPM Min</label>
                  <span className="text-xs font-mono text-amber-500">{form.bpmMin}</span>
                </div>
                <input 
                  type="range" min="60" max="110" 
                  value={form.bpmMin} 
                  onChange={(e) => setForm({...form, bpmMin: parseInt(e.target.value)})}
                  className="w-full accent-amber-500 h-1.5 bg-slate-800 rounded-lg appearance-none cursor-pointer" 
