    mood: Mood.CHILL,
    provider: MusicProvider.BEATOVEN,
    bpmMin: 70,
    bpmMax: 90,
    duration: 180,
    count: 3,
    titleBase: 'Lofi Vibes'
  });
  const [tracks, setTracks] = useState<Track[]>([]);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [isAudioLoading, setIsAudioLoading] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [audioDuration, setAudioDuration] = useState(0);

  const audioRef = useRef<HTMLAudioElement>(new Audio());

  useEffect(() => {
    setTracks(getTracks());
    const audio = audioRef.current;

    const handleTimeUpdate = () => setCurrentTime(audio.currentTime);
    const handleLoadedMetadata = () => {
      setAudioDuration(audio.duration);
      setIsAudioLoading(false);
    };
    const handleWaiting = () => setIsAudioLoading(true);
    const handlePlaying = () => setIsAudioLoading(false);
    const handleEnded = () => {
      setPlayingId(null);
      setCurrentTime(0);
    };

    audio.addEventListener('timeupdate', handleTimeUpdate);
    audio.addEventListener('loadedmetadata', handleLoadedMetadata);
    audio.addEventListener('waiting', handleWaiting);
    audio.addEventListener('playing', handlePlaying);
    audio.addEventListener('ended', handleEnded);

    return () => {
      audio.pause();
      audio.removeEventListener('timeupdate', handleTimeUpdate);
      audio.removeEventListener('loadedmetadata', handleLoadedMetadata);
      audio.removeEventListener('waiting', handleWaiting);
      audio.removeEventListener('playing', handlePlaying);
      audio.removeEventListener('ended', handleEnded);
    };
  }, []);

  const handleAiAssist = async () => {
    if (!prompt.trim()) return;
    setIsAiLoading(true);
    try {
      const result = await getAIAssistantParams(prompt);
      setForm({
        ...form,
        mood: result.mood,
        bpmMin: result.bpmRange.min,
        bpmMax: result.bpmRange.max,
        duration: result.suggestedDuration,
        titleBase: result.suggestedTitle
      });
    } catch (err) {
      console.error(err);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    try {
      const newTracks = await batchGenerateTracks(form.count, {
        mood: form.mood,
        provider: form.provider,
        bpmMin: form.bpmMin,
        bpmMax: form.bpmMax,
        durationSeconds: form.duration,
        titleBase: form.titleBase
      });
      newTracks.forEach(saveTrack);
      setTracks(getTracks());
    } catch (err) {
      alert("Error generating tracks. Please try again.");
    } finally {
      setIsGenerating(false);
    }
  };

  const formatTime = (seconds: number) => {
    if (isNaN(seconds)) return '0:00';
    const mins = Math.floor(seconds / 60);
    const secs = Math.floor(seconds % 60);
    return `${mins}:${secs.toString().padStart(2, '0')}`;
  };

  const handlePlay = (track: Track) => {
    const audio = audioRef.current;
    if (playingId === track.id) {
      audio.pause();
      setPlayingId(null);
    } else {
      setIsAudioLoading(true);
      audio.src = track.audioUrl;
      audio.play().catch(err => {
        console.error("Audio playback failed", err);
        setIsAudioLoading(false);
      });
      setPlayingId(track.id);
    }
  };

  const handleSeek = (e: React.ChangeEvent<HTMLInputElement>) => {
    const time = parseFloat(e.target.value);
    audioRef.current.currentTime = time;
    setCurrentTime(time);
  };

  const handleDelete = (id: string) => {
    if (window.confirm("Delete this track?")) {
      deleteTrack(id);
      if (playingId === id) {
        audioRef.current.pause();
        setPlayingId(null);
      }
      setTracks(getTracks());
