import { GoogleGenAI } from "@google/genai";

export const generateLofiBackground = async (prompt: string, aspectRatio: '16:9' | '9:16' = '16:9') => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: `Lofi aesthetic, high quality, loopable: ${prompt}`,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: aspectRatio
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) throw new Error("Video generation failed to return a URI.");

    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (error) {
    console.error("Video generation error:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Track } from '../types';
import { Play, Pause, SkipForward, SkipBack, Volume2, Loader2 } from 'lucide-react';

interface MixPlayerProps {
  tracks: Track[];
  crossfade: number;
}

export const MixPlayer: React.FC<MixPlayerProps> = ({ tracks, crossfade }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [progress, setProgress] = useState(0);
  const [isLoading, setIsLoading] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const nextSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const startTimeRef = useRef<number>(0);
  const gainNodeRef = useRef<GainNode | null>(null);

  const stopAll = () => {
    if (currentSourceRef.current) {
      currentSourceRef.current.stop();
      currentSourceRef.current = null;
    }
    if (nextSourceRef.current) {
      nextSourceRef.current.stop();
      nextSourceRef.current = null;
    }
    setIsPlaying(false);
    setProgress(0);
  };

  const playTrack = async (index: number) => {
    if (!tracks[index]) return;
    setIsLoading(true);

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      gainNodeRef.current = audioContextRef.current.createGain();
      gainNodeRef.current.connect(audioContextRef.current.destination);
    }

    try {
      const response = await fetch(tracks[index].audioUrl);
      const arrayBuffer = await response.arrayBuffer();
      const audioBuffer = await audioContextRef.current.decodeAudioData(arrayBuffer);

      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(gainNodeRef.current!);

      currentSourceRef.current = source;
      source.start(0);
      setIsPlaying(true);
      setCurrentIndex(index);
      startTimeRef.current = audioContextRef.current.currentTime;

      source.onended = () => {
        if (index + 1 < tracks.length) {
          playTrack(index + 1);
        } else {
          setIsPlaying(false);
        }
      };
    } catch (err) {
      console.error("Playback error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  const togglePlay = () => {
    if (isPlaying) {
      stopAll();
    } else {
      playTrack(currentIndex);
    }
  };

  return (
    <div className="bg-slate-900 border border-slate-800 rounded-2xl p-4 flex items-center space-x-6 shadow-xl">
      <button 
        onClick={togglePlay}
        disabled={tracks.length === 0 || isLoading}
        className="p-4 bg-amber-500 text-slate-950 rounded-full hover:bg-amber-600 transition-all disabled:opacity-50"
      >
        {isLoading ? <Loader2 className="animate-spin" /> : (isPlaying ? <Pause /> : <Play />)}
      </button>

      <div className="flex-1">
        <div className="flex justify-between items-end mb-2">
          <div>
            <div className="text-xs font-bold text-slate-500 uppercase tracking-widest mb-1">Now Previewing</div>
            <div className="text-sm font-bold text-white truncate">
              {tracks[currentIndex]?.title || "No tracks loaded"}
            </div>
          </div>
          <div className="text-[10px] font-mono text-slate-500">
            {currentIndex + 1} / {tracks.length}
          </div>
        </div>
        <div className="h-1.5 bg-slate-800 rounded-full overflow-hidden">
          <div className="h-full bg-amber-500 transition-all duration-300" style={{ width: `${progress}%` }} />
        </div>
      </div>

      <div className="flex items-center space-x-2 text-slate-400">
        <Volume2 size={18} />
        <div className="w-20 h-1 bg-slate-800 rounded-full">
          <div className="w-3/4 h-full bg-slate-500 rounded-full" />
        </div>
      </div>
    </div>
  );
};

