import { GoogleGenAI } from "@google/genai";

/**
 * Generates a high-quality, loopable lofi background.
 * For character consistency (Lo-Fi Girl style), we inject 
 * specific aesthetic markers into the prompt.
 */
export const generateLofiBackground = async (
  sceneDescription: string, 
  mood: string = 'chill',
  aspectRatio: '16:9' | '9:16' = '16:9'
) => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  // Refined prompt engineering for the "LoFi Girl" aesthetic
  const basePrompt = `Lofi anime style, studio ghibli aesthetic, flat colors, cozy lighting, loopable background, subtle animation. Scene: ${sceneDescription}. Mood: ${mood}. High resolution, 2D art.`;

  try {
    let operation = await ai.models.generateVideos({
      model: 'veo-3.1-fast-generate-preview',
      prompt: basePrompt,
      config: {
        numberOfVideos: 1,
        resolution: '720p',
        aspectRatio: aspectRatio
      }
    });

    while (!operation.done) {
      await new Promise(resolve => setTimeout(resolve, 10000));
      operation = await ai.operations.getVideosOperation({ operation: operation });
    }

    const downloadLink = operation.response?.generatedVideos?.[0]?.video?.uri;
    if (!downloadLink) throw new Error("Video generation failed.");

    const response = await fetch(`${downloadLink}&key=${process.env.API_KEY}`);
    const blob = await response.blob();
    return URL.createObjectURL(blob);
  } catch (error) {
    console.error("Video generation error:", error);
    throw error;
  }
};

import React, { useState, useEffect, useRef } from 'react';
import { Track } from '../types';
import { Play, Pause, Volume2, Loader2, Maximize2 } from 'lucide-react';

interface MixPlayerProps {
  tracks: Track[];
  crossfade: number;
  videoUrl?: string | null;
}

export const MixPlayer: React.FC<MixPlayerProps> = ({ tracks, crossfade, videoUrl }) => {
  const [isPlaying, setIsPlaying] = useState(false);
  const [currentIndex, setCurrentIndex] = useState(0);
  const [progress, setProgress] = useState(0);
  const [isLoading, setIsLoading] = useState(false);

  const audioContextRef = useRef<AudioContext | null>(null);
  const currentSourceRef = useRef<AudioBufferSourceNode | null>(null);
  const gainNodeRef = useRef<GainNode | null>(null);
  const animationFrameRef = useRef<number>(0);
  const startTimeRef = useRef<number>(0);

  const updateProgress = () => {
    if (!isPlaying || !audioContextRef.current || !currentSourceRef.current?.buffer) return;

    const elapsed = audioContextRef.current.currentTime - startTimeRef.current;
    const duration = currentSourceRef.current.buffer.duration;
    setProgress((elapsed / duration) * 100);

    animationFrameRef.current = requestAnimationFrame(updateProgress);
  };

  const stopAll = () => {
    if (currentSourceRef.current) {
      try { currentSourceRef.current.stop(); } catch(e) {}
      currentSourceRef.current = null;
    }
    cancelAnimationFrame(animationFrameRef.current);
    setIsPlaying(false);
    setProgress(0);
  };

  const playTrack = async (index: number) => {
    if (!tracks[index]) return;
    setIsLoading(true);

    if (!audioContextRef.current) {
      audioContextRef.current = new (window.AudioContext || (window as any).webkitAudioContext)();
      gainNodeRef.current = audioContextRef.current.createGain();
      gainNodeRef.current.connect(audioContextRef.current.destination);
    }

    try {
      const response = await fetch(tracks[index].audioUrl);
      const arrayBuffer = await response.arrayBuffer();
      const audioBuffer = await audioContextRef.current.decodeAudioData(arrayBuffer);

      const source = audioContextRef.current.createBufferSource();
      source.buffer = audioBuffer;
      source.connect(gainNodeRef.current!);

      currentSourceRef.current = source;
      startTimeRef.current = audioContextRef.current.currentTime;
      source.start(0);
      setIsPlaying(true);
      setCurrentIndex(index);
      updateProgress();

      source.onended = () => {
        const nextIndex = (index + 1) % tracks.length; // Loop for "Radio" mode
        playTrack(nextIndex);
      };
    } catch (err) {
      console.error("Playback error:", err);
    } finally {
      setIsLoading(false);
    }
  };

  const togglePlay = () => {
    if (isPlaying) {
      stopAll();
    } else {
      playTrack(currentIndex);
    }
  };

  return (
    <div className="relative group rounded-3xl overflow-hidden border border-slate-800 shadow-2xl bg-slate-900/50 backdrop-blur-xl">
      {/* Visual Background - The "Live Stream" look */}
      <div className="aspect-video w-full bg-slate-950 relative overflow-hidden">
        {videoUrl ? (
          <video 
            src={videoUrl} 
            autoPlay 
            loop 
            muted 
            className="w-full h-full object-cover opacity-60 group-hover:opacity-80 transition-opacity duration-700"
          />
        ) : (
          <div className="w-full h-full flex flex-col items-center justify-center space-y-4">
             <div className="w-20 h-20 border-4 border-slate-800 border-t-amber-500 rounded-full animate-spin-slow" />
             <p className="text-slate-600 text-[10px] uppercase tracking-widest font-bold">Awaiting Visual Assets</p>
          </div>
        )}

        {/* Stream Overlay Info */}
        <div className="absolute inset-0 p-6 flex flex-col justify-between pointer-events-none">
          <div className="flex justify-between items-start">
            <div className="bg-slate-950/80 backdrop-blur-md px-3 py-1.5 rounded-lg border border-slate-800 flex items-center space-x-2">
              <div className="w-2 h-2 rounded-full bg-rose-500 animate-pulse" />
              <span className="text-[10px] font-bold uppercase tracking-widest text-white">Live Stream Preview</span>
            </div>
            <button className="p-2 bg-slate-950/50 rounded-lg text-slate-400 pointer-events-auto hover:text-white transition-colors">
              <Maximize2 size={16} />
            </button>
          </div>

          <div className="bg-slate-950/80 backdrop-blur-md p-4 rounded-2xl border border-slate-800 w-fit max-w-[80%]">
            <div className="text-[10px] text-amber-500 font-bold uppercase tracking-widest mb-1">Now Playing</div>
            <div className="text-sm font-bold text-white truncate">{tracks[currentIndex]?.title || "Radio Offline"}</div>
            <div className="text-[10px] text-slate-500 font-mono mt-0.5">{tracks[currentIndex]?.bpm} BPM • Loop Active</div>
          </div>
        </div>
      </div>

      {/* Control Bar */}
      <div className="p-4 flex items-center space-x-4">
        <button 
          onClick={togglePlay}
          disabled={tracks.length === 0 || isLoading}
          className="p-3 bg-amber-500 text-slate-950 rounded-xl hover:bg-amber-600 transition-all disabled:opacity-50"
        >
          {isLoading ? <Loader2 className="animate-spin w-5 h-5" /> : (isPlaying ? <Pause size={20} /> : <Play size={20} />)}
        </button>

        <div className="flex-1">
          <div className="h-1 bg-slate-800 rounded-full overflow-hidden">
            <div className="h-full bg-amber-500 transition-all duration-300" style={{ width: `${progress}%` }} />
          </div>
        </div>

        <div className="flex items-center space-x-2 text-slate-500 bg-slate-950/50 px-3 py-2 rounded-xl border border-slate-800">
          <Volume2 size={16} />
          <div className="w-16 h-0.5 bg-slate-800 rounded-full">
            <div className="w-3/4 h-full bg-slate-400 rounded-full" />
          </div>
        </div>
      </div>
    </div>
  );
};

