import { batchGenerateTracks } from '../services/musicService';
import { saveTrack, getTracks, deleteTrack, toggleFavorite } from '../lib/storage';
import { InspirationPanel } from './InspirationPanel';
import { Sparkles, Loader2, Play, Pause, Trash2, Heart, Music, Cpu, Zap, Activity, Clock, Volume2 } from 'lucide-react';

const PROVIDER_STYLES: Record<MusicProvider, { color: string; bg: string; border: string; desc: string }> = {
  [MusicProvider.BEATOVEN]: { color: 'text-amber-400', bg: 'bg-amber-500/10', border: 'border-amber-500/20', desc: 'Mood-based structural lofi compositions.' },
  [MusicProvider.SOUNDRAW]: { color: 'text-rose-400', bg: 'bg-rose-500/10', border: 'border-rose-500/20', desc: 'Highly customizable beat loops.' },
  [MusicProvider.MUBERT]: { color: 'text-blue-400', bg: 'bg-blue-500/10', border: 'border-blue-500/20', desc: 'Infinite generative ambient flows.' },
  [MusicProvider.SOUNDFUL]: { color: 'text-emerald-400', bg: 'bg-emerald-500/10', border: 'border-emerald-500/20', desc: 'Studio-grade high-fidelity masters.' },
};

export const TrackGenerator: React.FC = () => {
  const [prompt, setPrompt] = useState('');
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [isGenerating, setIsGenerating] = useState(false);
  const [form, setForm] = useState({
    mood: Mood.CHILL,
    provider: MusicProvider.BEATOVEN,
    bpmMin: 70,
    bpmMax: 90,
    duration: 180,
    count: 3,
    titleBase: 'Lofi Vibes'
  });
  const [tracks, setTracks] = useState<Track[]>([]);
  const [playingId, setPlayingId] = useState<string | null>(null);
  const [isAudioLoading, setIsAudioLoading] = useState(false);
  const [currentTime, setCurrentTime] = useState(0);
  const [audioDuration, setAudioDuration] = useState(0);

  const audioRef = useRef<HTMLAudioElement>(new Audio());

  useEffect(() => {
    setTracks(getTracks());
    const audio = audioRef.current;
    const handleTimeUpdate = () => setCurrentTime(audio.currentTime);
    const handleLoadedMetadata = () => {
      setAudioDuration(audio.duration);
      setIsAudioLoading(false);
    };
    const handleEnded = () => {
      setPlayingId(null);
      setCurrentTime(0);
    };
    audio.addEventListener('timeupdate', handleTimeUpdate);
    audio.addEventListener('loadedmetadata', handleLoadedMetadata);
    audio.addEventListener('ended', handleEnded);
    return () => {
      audio.pause();
      audio.removeEventListener('timeupdate', handleTimeUpdate);
      audio.removeEventListener('loadedmetadata', handleLoadedMetadata);
      audio.removeEventListener('ended', handleEnded);
    };
  }, []);

  const handleAiAssist = async () => {
    if (!prompt.trim()) return;
    setIsAiLoading(true);
    try {
      const result = await getAIAssistantParams(prompt);
      setForm({ ...form, mood: result.mood, bpmMin: result.bpmRange.min, bpmMax: result.bpmRange.max, duration: result.suggestedDuration, titleBase: result.suggestedTitle });
    } catch (err) {
      console.error(err);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleUseTemplate = (category: string) => {
    const templates: Record<string, string> = {
      'Study': 'Quiet rainy afternoon study session with warm tea, soft piano, and paper scratching sounds',
      'Night': 'Synthwave night drive through a neon city, 80s aesthetic, dreamy pads',
      'Sleep': 'Very slow ambient lofi with distant waves and moonlight shining through a bedroom window'
    };
    if (templates[category]) {
      setPrompt(templates[category]);
    }
  };

  const handleGenerate = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsGenerating(true);
    try {
      const newTracks = await batchGenerateTracks(form.count, {
        mood: form.mood,
        provider: form.provider,
        bpmMin: form.bpmMin,
        bpmMax: form.bpmMax,
        durationSeconds: form.duration,
        titleBase: form.titleBase
      });
      newTracks.forEach(saveTrack);
      setTracks(getTracks());
    } catch (err) {
      alert("Error generating tracks.");
    } finally {
      setIsGenerating(false);
    }
  };

  const handlePlay = (track: Track) => {
    const audio = audioRef.current;
    if (playingId === track.id) {
      audio.pause();
      setPlayingId(null);
    } else {
      setIsAudioLoading(true);
      audio.src = track.audioUrl;
      audio.play().catch(() => setIsAudioLoading(false));
      setPlayingId(track.id);
    }
  };

  return (
    <div className="relative space-y-6 lg:space-y-8 animate-in fade-in slide-in-from-bottom-4 duration-700">
      <InspirationPanel onUseTemplate={handleUseTemplate} />

      <header>
        <h2 className="text-2xl lg:text-3xl font-bold text-white mb-1 lg:mb-2">Track Lab</h2>
        <p className="text-slate-400 text-sm lg:text-base">Use the Inspiration Studio on the right to reference Lo-Fi Girl vibes.</p>
      </header>

      <div className="grid grid-cols-1 lg:grid-cols-3 gap-6 lg:gap-8">
        <div className="lg:col-span-1 space-y-6">
          <section className="bg-slate-900/40 border border-slate-800 p-5 rounded-2xl space-y-4 shadow-xl backdrop-blur-md">
            <div className="flex items-center space-x-2 text-amber-500">
              <Sparkles className="w-5 h-5" />
              <h3 className="font-bold">Scene Assistant</h3>
            </div>
            <textarea 
              className="w-full bg-slate-950 border border-slate-800 rounded-xl p-4 text-sm focus:border-amber-500/50 outline-none min-h-[100px]"
              placeholder="Describe the vibe or choose a template from the Inspiration panel..."
              value={prompt}
              onChange={(e) => setPrompt(e.target.value)}
            />
            <button 
              onClick={handleAiAssist}
              disabled={isAiLoading || !prompt.trim()}
              className="w-full py-3 bg-amber-500/10 text-amber-500 border border-amber-500/20 rounded-xl text-sm font-semibold hover:bg-amber-500/20"
            >
              {isAiLoading ? <Loader2 className="w-4 h-4 animate-spin mx-auto" /> : 'Apply Scene Constraints'}
            </button>
          </section>

          <form onSubmit={handleGenerate} className="bg-slate-900/40 border border-slate-800 p-5 rounded-2xl space-y-5">
            <div>
              <label className="block text-[10px] font-bold text-slate-500 uppercase tracking-widest mb-3">AI Generation Engine</label>
              <div className="grid grid-cols-2 gap-2">
                {Object.values(MusicProvider).map(p => (
                  <button key={p} type="button" onClick={() => setForm({...form, provider: p})}
                    className={`px-3 py-2.5 rounded-xl text-[11px] font-bold border transition-all ${form.provider === p ? 'bg-amber-500/10 border-amber-500/50 text-white' : 'border-slate-800 text-slate-500'}`}
                  >
                    {p}
                  </button>
                ))}
              </div>
            </div>
            <button type="submit" disabled={isGenerating} className="w-full py-4 bg-amber-500 hover:bg-amber-600 text-slate-950 rounded-2xl font-bold flex items-center justify-center space-x-2">
              {isGenerating ? <Loader2 className="animate-spin" /> : <Activity />}
              <span>{isGenerating ? 'Synthesizing...' : 'Generate Batch'}</span>
            </button>
          </form>
        </div>

        <div className="lg:col-span-2">
          <section className="bg-slate-900/40 border border-slate-800 rounded-2xl overflow-hidden backdrop-blur-md shadow-2xl h-full flex flex-col min-h-[500px]">
            <div className="p-6 border-b border-slate-800 flex justify-between items-center">
              <h3 className="text-lg font-bold text-white flex items-center space-x-2">
                <Music size={20} className="text-amber-500" />
                <span>Track Vault</span>
              </h3>
            </div>
            <div className="flex-1 overflow-y-auto p-4 space-y-2">
              {tracks.map(track => (
                <div key={track.id} className="flex items-center justify-between p-3 rounded-xl bg-slate-950/50 border border-slate-800 hover:border-slate-700 group transition-all">
                  <div className="flex items-center space-x-4">
                    <button onClick={() => handlePlay(track)} className="p-2 bg-slate-800 rounded-lg text-slate-400 group-hover:text-amber-500 transition-colors">
                      {playingId === track.id ? <Pause size={16} /> : <Play size={16} />}
                    </button>
                    <div>
                      <div className="text-xs font-bold text-slate-100">{track.title}</div>
