          <p className="text-slate-400 text-sm">Design your 24/7 stream and batch content assets.</p>
        </div>
        <button onClick={generateExport} className="px-8 py-3 rounded-xl font-bold bg-amber-500 hover:bg-amber-400 text-slate-950 shadow-lg">
          Export Stream Bundle
        </button>
      </header>

      <MixPlayer tracks={mixTracks} crossfade={crossfade} videoUrl={videoUrl} />

      <div className="grid grid-cols-1 lg:grid-cols-12 gap-6 lg:gap-8">
        <div className="lg:col-span-4 flex flex-col space-y-3">
          <h3 className="text-[10px] font-bold text-slate-500 uppercase tracking-widest flex items-center space-x-2">
