import { GoogleGenAI, Type } from "@google/genai";
import { AIPromptResult, Mood } from "../types";

export const getAIAssistantParams = async (prompt: string): Promise<AIPromptResult> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-flash-preview',
    contents: `Based on this lofi scene description, generate musical parameters: "${prompt}"`,
    config: {
      systemInstruction: "You are a specialized music producer assistant for Lofi Hip Hop. Convert descriptive scenes into structured musical parameters. Map moods to: Chill, Night, Rainy, Focus, Coding, Sleep. Provide a calm reasoning.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          mood: { type: Type.STRING, enum: Object.values(Mood) },
          bpmRange: {
            type: Type.OBJECT,
            properties: {
              min: { type: Type.NUMBER },
              max: { type: Type.NUMBER }
            }
          },
          suggestedDuration: { type: Type.NUMBER },
          suggestedTitle: { type: Type.STRING },
          reasoning: { type: Type.STRING }
        },
        required: ["mood", "bpmRange", "suggestedDuration", "suggestedTitle", "reasoning"]
      }
    }
  });

  try {
    return JSON.parse(response.text.trim()) as AIPromptResult;
  } catch (error) {
    return {
      mood: Mood.CHILL,
      bpmRange: { min: 80, max: 90 },
      suggestedDuration: 180,
      suggestedTitle: "Dreamscape",
      reasoning: "Defaulted to chill vibe."
    };
  }
};

/**
 * Specifically designed to take a reference "vibe" (like Lofi Girl Study)
 * and generate an IMPROVED version with modern production standards.
 */
export const replicateAesthetic = async (category: string): Promise<AIPromptResult & { improvementSuggestions: string[] }> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const response = await ai.models.generateContent({
    model: 'gemini-3-pro-preview',
    contents: `Reference Channel Category: ${category}. Generate production parameters for an 'Improved' version that maintains the vibe but increases audio depth.`,
    config: {
      systemInstruction: "You are a world-class Lofi Producer. Analyze the 'Lofi Girl' aesthetic for the given category. Your goal is to replicate its core DNA (BPM, Mood) but suggest 'improvements' like 'added binaural field recordings', 'analog tape saturation', or 'sophisticated jazz harmony'.",
      responseMimeType: "application/json",
      responseSchema: {
        type: Type.OBJECT,
        properties: {
          mood: { type: Type.STRING, enum: Object.values(Mood) },
          bpmRange: {
            type: Type.OBJECT,
            properties: {
              min: { type: Type.NUMBER },
              max: { type: Type.NUMBER }
            }
          },
          suggestedDuration: { type: Type.NUMBER },
          suggestedTitle: { type: Type.STRING },
          reasoning: { type: Type.STRING },
          improvementSuggestions: {
            type: Type.ARRAY,
            items: { type: Type.STRING }
          }
        },
        required: ["mood", "bpmRange", "suggestedDuration", "suggestedTitle", "reasoning", "improvementSuggestions"]
      }
    }
  });

  return JSON.parse(response.text.trim());
};

